import React, { useState, useEffect } from 'react';
import { Bell, Settings, User, ChevronDown, Moon, Sun, LogOut, BookOpen, GraduationCap } from 'lucide-react';
import Course from './Course.jsx';
import InstructorDashboard from './InstructorDashboard.jsx';
import StudentDashboard from './components/StudentDashboard.jsx';
import LoginModal from './components/LoginModal.jsx';
import LoadingSpinner from './components/LoadingSpinner.jsx';
import ErrorBoundary from './components/ErrorBoundary.jsx';
import { ToastProvider, useToast } from './components/Toast.jsx';
import { validateCourse } from './utils/validation.js';
import useCourseStore from './store/courseStore.js';
import useAuthStore from './store/authStore.js';
import dataService from './services/api.js';

const AppContent = () => {
  const [currentPage, setCurrentPage] = useState('courses');
  const [showUserMenu, setShowUserMenu] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const { showToast } = useToast();

  const { user, isAuthenticated, logout } = useAuthStore();
  const { courses, notifications, loading, error, setCourses, addCourse, updateCourse, deleteCourse, setLoading, setError, getStats, markNotificationRead } = useCourseStore();

  const stats = getStats();

  useEffect(() => {
    if (courses.length === 0) loadDefaultCourses();
    const darkMode = localStorage.getItem('darkMode') === 'true';
    setIsDarkMode(darkMode);
    if (darkMode) document.documentElement.classList.add('dark');
  }, []);

  const loadDefaultCourses = () => {
    const defaultCourses = [
      {id:1,title:'Full Stack Web Development',desc:'Master HTML, CSS, JS, React, Node.js and build dynamic web apps.',level:'Intermediate',rating:'4.8',time:'8h 30m',cat:'development',instructor:'John Parker',img:'https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=400&h=200&fit=crop',price:99,enrolled:1250,progress:65},
      {id:2,title:'Machine Learning Basics',desc:'Understand algorithms, train models, and deploy ML apps with Python.',level:'Advanced',rating:'4.9',time:'10h',cat:'ai',instructor:'Dr. Aisha Khan',img:'https://images.unsplash.com/photo-1581090700227-1e37b190418e?w=400&h=200&fit=crop',price:149,enrolled:890,progress:0},
      {id:3,title:'UI/UX Design for Beginners',desc:'Learn Figma, typography, wireframing, and design psychology.',level:'Beginner',rating:'4.6',time:'6h 45m',cat:'design',instructor:'Elena Rose',img:'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=400&h=200&fit=crop',price:79,enrolled:2100,progress:100}
    ];
    setCourses(defaultCourses);
  };

  const handleCourseAction = async (action, courseData, courseId) => {
    try {
      setLoading(true);
      let result;

      switch (action) {
        case 'add':
          const validation = validateCourse(courseData);
          if (!validation.isValid) throw new Error(validation.errors[0]);
          result = { ...courseData, id: Date.now(), enrolled: 0, rating: '5.0' };
          addCourse(result);
          showToast('Course created successfully!', 'success');
          break;
        case 'update':
          updateCourse(courseId, courseData);
          showToast('Course updated successfully!', 'success');
          break;
        case 'delete':
          deleteCourse(courseId);
          showToast('Course deleted successfully!', 'success');
          break;
      }

      try {
        await dataService[action === 'add' ? 'createCourse' : action === 'update' ? 'updateCourse' : 'deleteCourse'](action === 'delete' ? courseId : result || courseData);
      } catch (apiErr) {
        console.log('API sync failed, operation saved locally');
      }

      return result;
    } catch (err) {
      showToast(`Failed to ${action} course: ${err.message}`, 'error');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const handleNotificationClick = (notification) => {
    markNotificationRead(notification.id);
    setShowNotifications(false);
  };

  const handleLogout = () => {
    logout();
    setCurrentPage('courses');
    setShowUserMenu(false);
    showToast('Logged out successfully', 'info');
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-purple-50 flex items-center justify-center">
        <div className="text-center">
          <div className="w-20 h-20 bg-gradient-to-r from-blue-600 to-purple-600 rounded-2xl flex items-center justify-center mx-auto mb-6">
            <span className="text-white font-bold text-2xl">R</span>
          </div>
          <h1 className="text-4xl font-bold text-gray-900 mb-4">Welcome to RiseGen</h1>
          <p className="text-gray-600 mb-8 max-w-md mx-auto">Choose your role to get started with our learning platform</p>
          <button onClick={() => setShowLoginModal(true)} className="bg-gradient-to-r from-blue-600 to-purple-600 text-white px-8 py-3 rounded-xl font-semibold hover:from-blue-700 hover:to-purple-700 transition-all">
            Get Started
          </button>
        </div>
        {showLoginModal && <LoginModal onClose={() => setShowLoginModal(false)} />}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white shadow-lg border-b fixed w-full z-50 backdrop-blur-md bg-white/95">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center space-x-8">
              <div className="flex items-center space-x-2">
                <div className="w-8 h-8 bg-gradient-to-r from-blue-600 to-purple-600 rounded-lg flex items-center justify-center">
                  <span className="text-white font-bold text-sm">R</span>
                </div>
                <span className="font-bold text-xl bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">RiseGen</span>
              </div>

              <div className="flex space-x-1">
                <button onClick={() => setCurrentPage('courses')} className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${currentPage === 'courses' ? 'bg-blue-100 text-blue-700 shadow-sm' : 'text-gray-600 hover:text-blue-600 hover:bg-blue-50'}`}>
                  <BookOpen className="w-4 h-4 inline mr-1" />All Courses ({stats.totalCourses})
                </button>

                {user?.role === 'student' && (
                  <button onClick={() => setCurrentPage('dashboard')} className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${currentPage === 'dashboard' ? 'bg-blue-100 text-blue-700 shadow-sm' : 'text-gray-600 hover:text-blue-600 hover:bg-blue-50'}`}>
                    <User className="w-4 h-4 inline mr-1" />My Learning
                  </button>
                )}

                {user?.role === 'instructor' && (
                  <button onClick={() => setCurrentPage('instructor')} className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${currentPage === 'instructor' ? 'bg-purple-100 text-purple-700 shadow-sm' : 'text-gray-600 hover:text-purple-600 hover:bg-purple-50'}`}>
                    <GraduationCap className="w-4 h-4 inline mr-1" />Instructor Panel
                  </button>
                )}
              </div>
            </div>

            <div className="flex items-center space-x-4">
              <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors">
                {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
              </button>

              <div className="relative">
                <button onClick={() => setShowNotifications(!showNotifications)} className="p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors relative">
                  <Bell className="w-5 h-5" />
                  {stats.unreadNotifications > 0 && (
                    <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-xs rounded-full flex items-center justify-center animate-pulse">
                      {stats.unreadNotifications > 9 ? '9+' : stats.unreadNotifications}
                    </span>
                  )}
                </button>

                {showNotifications && (
                  <div className="absolute right-0 mt-2 w-80 bg-white rounded-xl shadow-xl border border-gray-200 py-2 z-50">
                    <div className="px-4 py-2 border-b border-gray-100">
                      <h3 className="font-semibold text-gray-900">Notifications</h3>
                    </div>
                    <div className="max-h-64 overflow-y-auto">
                      {notifications.map(notification => (
                        <button key={notification.id} onClick={() => handleNotificationClick(notification)} className={`w-full text-left px-4 py-3 hover:bg-gray-50 border-l-4 transition-colors ${notification.unread ? 'border-blue-500 bg-blue-50/30' : 'border-transparent'}`}>
                          <p className="text-sm text-gray-900">{notification.message}</p>
                          <p className="text-xs text-gray-500 mt-1">{notification.time}</p>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>

              <div className="relative">
                <button onClick={() => setShowUserMenu(!showUserMenu)} className="flex items-center space-x-2 p-2 text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors">
                  <div className="w-8 h-8 bg-gradient-to-r from-purple-500 to-pink-500 rounded-full flex items-center justify-center">
                    <User className="w-4 h-4 text-white" />
                  </div>
                  <span className="text-sm font-medium hidden sm:block">{user?.name}</span>
                  <ChevronDown className="w-4 h-4" />
                </button>

                {showUserMenu && (
                  <div className="absolute right-0 mt-2 w-56 bg-white rounded-xl shadow-xl border border-gray-200 py-2 z-50">
                    <div className="px-4 py-2 border-b border-gray-100">
                      <p className="text-sm font-medium text-gray-900">{user?.name}</p>
                      <p className="text-xs text-gray-500 capitalize">{user?.role}</p>
                    </div>
                    <button className="w-full flex items-center px-4 py-2 text-sm text-gray-700 hover:bg-gray-50">
                      <Settings className="w-4 h-4 mr-3" />Settings
                    </button>
                    <hr className="my-2" />
                    <button onClick={handleLogout} className="w-full flex items-center px-4 py-2 text-sm text-red-600 hover:bg-red-50">
                      <LogOut className="w-4 h-4 mr-3" />Logout
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </nav>

      <div className="pt-16">
        {loading && <div className="flex items-center justify-center min-h-screen"><LoadingSpinner size="large" text="Loading..." /></div>}
        {error && (
          <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mx-4 mt-4">
            <strong>Error: </strong>{error}
          </div>
        )}
        {!loading && !error && (
          <>
            {currentPage === 'courses' && <Course courses={courses} />}
            {currentPage === 'dashboard' && user?.role === 'student' && <StudentDashboard />}
            {currentPage === 'instructor' && user?.role === 'instructor' && (
              <InstructorDashboard courses={courses} onAddCourse={(data) => handleCourseAction('add', data)} onUpdateCourse={(id, data) => handleCourseAction('update', data, id)} onDeleteCourse={(id) => handleCourseAction('delete', null, id)} />
            )}
          </>
        )}
      </div>
    </div>
  );
};

const App = () => (
  <ErrorBoundary>
    <ToastProvider>
      <AppContent />
    </ToastProvider>
  </ErrorBoundary>
);

export default App;
